import { useState } from 'react';
import { CornerDownLeft, Sparkles, Wand2 } from 'lucide-react';

export function AIChatInput() {
  const [text, setText] = useState("");
  const maxChars = 200;

  const promptChips = [
    "Optimise my Tailwind layout",
    "Explain local-first SQLite WAL",
    "Write an interactive CSS ripple"
  ];

  const handleChipClick = (chip) => {
    if (text.length + chip.length <= maxChars) {
      setText((prev) => (prev ? `${prev} ${chip}` : chip));
    }
  };

  return (
    <div className="w-full max-w-xl mx-auto border border-border bg-card p-4 rounded-2xl shadow-xl text-foreground">
      {/* Prompt Chips Bar */}
      <div className="flex flex-wrap gap-2 mb-3">
        {promptChips.map((chip) => (
          <button
            key={chip}
            onClick={() => handleChipClick(chip)}
            className="flex items-center gap-1 px-3 py-1.5 rounded-full border border-border/80 bg-muted/30 hover:bg-muted text-xs font-medium transition-all text-muted-foreground hover:text-foreground"
          >
            <Sparkles className="h-3 w-3 text-primary" />
            <span>{chip}</span>
          </button>
        ))}
      </div>

      {/* Main Input Textarea Area */}
      <div className="relative border border-border focus-within:border-primary/80 focus-within:ring-2 focus-within:ring-primary/20 rounded-xl bg-background p-3 transition-all">
        <textarea
          value={text}
          onChange={(e) => setText(e.target.value.slice(0, maxChars))}
          placeholder="Ask OpenBlocks agent or write query..."
          rows={3}
          className="w-full resize-none bg-transparent text-sm focus:outline-none placeholder-muted-foreground text-foreground"
        />

        <div className="flex items-center justify-between border-t border-border/60 mt-3 pt-2 text-xs text-muted-foreground font-mono">
          <span>
            {text.length}/{maxChars} chars
          </span>

          <div className="flex items-center gap-2">
            <button 
              disabled={!text}
              className="p-1.5 rounded-lg hover:bg-muted text-muted-foreground hover:text-foreground transition-colors disabled:opacity-40"
              aria-label="Improve Prompt"
            >
              <Wand2 className="h-4 w-4" />
            </button>
            <button
              disabled={!text}
              className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-primary hover:bg-primary/95 text-primary-foreground font-bold uppercase transition-all disabled:opacity-40"
              aria-label="Send Prompt"
            >
              <span>Send</span>
              <CornerDownLeft className="h-3.5 w-3.5" />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';

export function MagneticGlowingButton() {
  const [coords, setCoords] = useState({ x: 0, y: 0 });
  const [isHovered, setIsHovered] = useState(false);

  const handleMouseMove = (e) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    setCoords({ x, y });
  };

  return (
    <div className="flex items-center justify-center p-8 bg-neutral-950 rounded-2xl border border-white/5">
      <button
        onMouseMove={handleMouseMove}
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
        className="relative group overflow-hidden px-8 py-4 rounded-xl border border-white/10 bg-[#121214] text-white font-bold text-sm tracking-wide transition-all duration-300 hover:scale-105 active:scale-98 shadow-2xl"
      >
        {/* Custom Glowing Radial Hover Layer */}
        {isHovered && (
          <span
            style={{
              left: coords.x,
              top: coords.y,
              pointerEvents: 'none'
            }}
            className="absolute -translate-x-1/2 -translate-y-1/2 h-32 w-32 rounded-full bg-gradient-to-br from-cyan-500 to-indigo-500 opacity-40 blur-2xl transition-all duration-100 animate-pulse"
          />
        )}

        <span className="relative z-10 flex items-center gap-2 group-hover:text-cyan-200 transition-colors">
          Unlock Premium Stack
        </span>
      </button>
    </div>
  );
}

